import React, { useState } from "react";
import "../styles/App.css";

const API_BASE = "http://localhost:8000";
const initialForm = { distance: "", relative_velocity: "" };
const STATUS_THEME = {
  SAFE: { border: "#2e7d32", text: "#1b5e20", bg: "#edf7ed" },
  CAUTION: { border: "#ed6c02", text: "#8a4b00", bg: "#fff4e5" },
  RISK: { border: "#d32f2f", text: "#8a1c1c", bg: "#fdecea" },
  "HIGH RISK": { border: "#b71c1c", text: "#7f0000", bg: "#ffebee" },
  COLLIDED: { border: "#4a148c", text: "#4a148c", bg: "#f3e5f5" },
};
const STATUS_ORDER = ["SAFE", "RISK", "HIGH RISK", "COLLIDED"];
const STATUS_COLORS = {
  SAFE: "#2e7d32",
  RISK: "#ef6c00",
  "HIGH RISK": "#c62828",
  COLLIDED: "#6a1b9a",
};
const STATUS_SCORE = {
  SAFE: 1,
  RISK: 2,
  "HIGH RISK": 3,
  COLLIDED: 4,
};

function ChartFrame({ title, children }) {
  return (
    <div className="chartCard">
      <div className="chartTitle">{title}</div>
      {children}
    </div>
  );
}

function EmptyChart({ text }) {
  return <div className="chartEmpty">{text}</div>;
}

function PieChart({ counts, total }) {
  if (!total) {
    return <EmptyChart text="No prediction data available." />;
  }

  const radius = 70;
  const circumference = 2 * Math.PI * radius;
  let offset = 0;

  return (
    <div className="chartWrap pieWrap">
      <svg viewBox="0 0 220 220" className="pieChart" aria-label="Status distribution">
        <g transform="translate(110 110) rotate(-90)">
          <circle cx="0" cy="0" r={radius} fill="none" stroke="#e5e7eb" strokeWidth="26" />
          {STATUS_ORDER.map((status) => {
            const value = counts[status] || 0;
            if (!value) {
              return null;
            }
            const segment = (value / total) * circumference;
            const circle = (
              <circle
                key={status}
                cx="0"
                cy="0"
                r={radius}
                fill="none"
                stroke={STATUS_COLORS[status]}
                strokeWidth="26"
                strokeDasharray={`${segment} ${circumference - segment}`}
                strokeDashoffset={-offset}
              />
            );
            offset += segment;
            return circle;
          })}
        </g>
        <text x="110" y="102" textAnchor="middle" className="chartCenterValue">
          {total}
        </text>
        <text x="110" y="124" textAnchor="middle" className="chartCenterLabel">
          Records
        </text>
      </svg>
      <div className="chartLegend">
        {STATUS_ORDER.map((status) => (
          <div key={status} className="legendRow">
            <span className="legendDot" style={{ background: STATUS_COLORS[status] }} />
            <span>{status}</span>
            <strong>{counts[status] || 0}</strong>
          </div>
        ))}
      </div>
    </div>
  );
}

function BarChart({ counts }) {
  const max = Math.max(...STATUS_ORDER.map((status) => counts[status] || 0), 1);

  return (
    <div className="barChart">
      {STATUS_ORDER.map((status) => {
        const value = counts[status] || 0;
        return (
          <div key={status} className="barRow">
            <div className="barMeta">
              <span>{status}</span>
              <strong>{value}</strong>
            </div>
            <div className="barTrack">
              <div
                className="barFill"
                style={{
                  width: `${(value / max) * 100}%`,
                  background: STATUS_COLORS[status],
                }}
              />
            </div>
          </div>
        );
      })}
    </div>
  );
}

function PolylineChart({ points, color, yFormatter, emptyText, yTicks }) {
  if (points.length < 2) {
    return <EmptyChart text={emptyText} />;
  }

  const width = 420;
  const height = 220;
  const padding = 28;
  const values = points.map((point) => point.value);
  const minValue = Math.min(...values);
  const maxValue = Math.max(...values);
  const range = maxValue - minValue || 1;

  const svgPoints = points
    .map((point, index) => {
      const x = padding + (index / (points.length - 1)) * (width - padding * 2);
      const y = height - padding - ((point.value - minValue) / range) * (height - padding * 2);
      return `${x},${y}`;
    })
    .join(" ");

  return (
    <div className="svgChartWrap">
      <svg viewBox={`0 0 ${width} ${height}`} className="svgChart">
        {[0, 0.5, 1].map((ratio) => {
          const y = padding + ratio * (height - padding * 2);
          const labelValue = maxValue - ratio * range;
          return (
            <g key={ratio}>
              <line x1={padding} y1={y} x2={width - padding} y2={y} className="gridLine" />
              <text x="8" y={y + 4} className="axisLabel">
                {yFormatter ? yFormatter(labelValue) : labelValue.toFixed(1)}
              </text>
            </g>
          );
        })}
        <polyline fill="none" stroke={color} strokeWidth="3" points={svgPoints} />
        {points.map((point, index) => {
          const x = padding + (index / (points.length - 1)) * (width - padding * 2);
          const y = height - padding - ((point.value - minValue) / range) * (height - padding * 2);
          return <circle key={point.label || index} cx={x} cy={y} r="4" fill={color} />;
        })}
        {yTicks || null}
      </svg>
    </div>
  );
}

function Histogram({ values }) {
  if (!values.length) {
    return <EmptyChart text="No distance data available." />;
  }

  const bins = 6;
  const min = Math.min(...values);
  const max = Math.max(...values);
  const span = max - min || 1;
  const binSize = span / bins;
  const counts = Array.from({ length: bins }, () => 0);

  values.forEach((value) => {
    const index = Math.min(Math.floor((value - min) / binSize), bins - 1);
    counts[index] += 1;
  });

  const maxCount = Math.max(...counts, 1);

  return (
    <div className="histogram">
      {counts.map((count, index) => {
        const start = min + index * binSize;
        const end = start + binSize;
        return (
          <div key={`${start}-${end}`} className="histBarGroup">
            <div className="histValue">{count}</div>
            <div className="histTrack">
              <div className="histFill" style={{ height: `${(count / maxCount) * 100}%` }} />
            </div>
            <div className="histLabel">
              {start.toFixed(1)}-{end.toFixed(1)}
            </div>
          </div>
        );
      })}
    </div>
  );
}

function ScatterPlot({ points }) {
  if (!points.length) {
    return <EmptyChart text="No paired distance and velocity data available." />;
  }

  const width = 420;
  const height = 220;
  const padding = 28;
  const xValues = points.map((point) => point.distance);
  const yValues = points.map((point) => point.relative_velocity);
  const minX = Math.min(...xValues);
  const maxX = Math.max(...xValues);
  const minY = Math.min(...yValues);
  const maxY = Math.max(...yValues);
  const xRange = maxX - minX || 1;
  const yRange = maxY - minY || 1;

  return (
    <div className="svgChartWrap">
      <svg viewBox={`0 0 ${width} ${height}`} className="svgChart">
        <line x1={padding} y1={height - padding} x2={width - padding} y2={height - padding} className="gridAxis" />
        <line x1={padding} y1={padding} x2={padding} y2={height - padding} className="gridAxis" />
        {points.map((point) => {
          const x = padding + ((point.distance - minX) / xRange) * (width - padding * 2);
          const y = height - padding - ((point.relative_velocity - minY) / yRange) * (height - padding * 2);
          return (
            <circle
              key={point.id}
              cx={x}
              cy={y}
              r="5"
              fill={STATUS_COLORS[point.predicted_status] || "#102542"}
              opacity="0.85"
            />
          );
        })}
        <text x={width / 2} y={height - 6} textAnchor="middle" className="axisLabel">
          Distance
        </text>
        <text x="10" y={height / 2} textAnchor="middle" className="axisLabel">
          Velocity
        </text>
      </svg>
    </div>
  );
}

function PredictView({
  form,
  loading,
  error,
  result,
  submittedData,
  onChange,
  onSubmit,
  onReset,
}) {
  const theme = result ? (STATUS_THEME[result.predicted_status] || STATUS_THEME.SAFE) : null;

  return (
    <section className="panel mainPanel">
      <div className="panelContent">
        <div className="panelColumn">
          <h2>Input</h2>
          <form onSubmit={onSubmit}>
            <div className="field">
              <label>Distance to Object (m)</label>
              <input
                type="number"
                name="distance"
                value={form.distance}
                onChange={onChange}
                placeholder="e.g. 15"
              />
            </div>

            <div className="field">
              <label>Relative Velocity (m/s)</label>
              <input
                type="number"
                name="relative_velocity"
                value={form.relative_velocity}
                onChange={onChange}
                placeholder="e.g. 10"
              />
            </div>

            {error && <div className="error">{error}</div>}

            <div className="buttonRow">
              <button type="submit" disabled={loading} className="button">
                {loading ? "Predicting..." : "Predict"}
              </button>
              <button type="button" onClick={onReset} className="resetButton">
                Reset
              </button>
            </div>
          </form>
        </div>

        <div className="panelColumn panelOutput">
          <h2>Output</h2>

          {!result && !loading && (
            <div className="placeholder">
              <p>Enter distance and relative velocity to generate a prediction.</p>
            </div>
          )}

          {loading && <div className="placeholder">Predicting...</div>}

          {result && theme && (
            <div
              className="statusBanner"
              style={{ background: theme.bg, border: `2px solid ${theme.border}` }}
            >
              <div>
                <div className="statusLabel" style={{ color: theme.text }}>
                  {result.predicted_status}
                </div>
                <div className="metricRow">
                  <span>Time To Collision</span>
                  <strong>{result.ttc === null ? "N/A" : `${result.ttc.toFixed(2)} s`}</strong>
                </div>
                <div className="messageText">{result.message}</div>
              </div>
            </div>
          )}

          {submittedData && (
            <div className="submittedData">
              <strong>Last Input</strong>
              <div>Distance: {submittedData.distance} m</div>
              <div>Relative Velocity: {submittedData.relative_velocity} m/s</div>
            </div>
          )}
        </div>
      </div>
    </section>
  );
}

function HistoryView({ history, histLoading }) {
  return (
    <section className="panel mainPanel">
      <div className="historyViewHeader">
        <h2>Prediction History</h2>
        <p>Recent ADAS-style predictions from the backend.</p>
      </div>

      <div className="historyCard">
        {histLoading ? <p>Loading...</p> : history.length === 0 ? <p>No predictions yet.</p> : (
          <table className="historyTable">
            <thead>
              <tr>
                <th>#</th>
                <th>Distance</th>
                <th>TTC</th>
                <th>Rel. Velocity</th>
                <th>Status</th>
              </tr>
            </thead>
            <tbody>
              {history.map((row) => (
                <tr key={row.id}>
                  <td>{row.id}</td>
                  <td>{row.distance.toFixed(1)} m</td>
                  <td>{row.ttc === null ? "N/A" : `${row.ttc.toFixed(2)} s`}</td>
                  <td>{row.relative_velocity.toFixed(1)} m/s</td>
                  <td>{row.predicted_status}</td>
                </tr>
              ))}
            </tbody>
          </table>
        )}
      </div>
    </section>
  );
}

function StatisticsView({ history, histLoading }) {
  if (histLoading) {
    return (
      <section className="panel mainPanel">
        <div className="historyViewHeader">
          <h2>Statistics</h2>
          <p>Loading prediction statistics...</p>
        </div>
      </section>
    );
  }

  const orderedHistory = [...history].reverse();
  const counts = STATUS_ORDER.reduce((acc, status) => ({ ...acc, [status]: 0 }), {});
  orderedHistory.forEach((row) => {
    counts[row.predicted_status] = (counts[row.predicted_status] || 0) + 1;
  });

  const ttcPoints = orderedHistory
    .filter((row) => row.ttc !== null)
    .map((row, index) => ({ label: row.id, value: row.ttc, index }));
  const trendPoints = orderedHistory.map((row, index) => ({
    label: row.id,
    value: STATUS_SCORE[row.predicted_status] || 1,
    index,
  }));
  const distanceValues = orderedHistory.map((row) => row.distance);
  const scatterPoints = orderedHistory.map((row) => ({
    id: row.id,
    distance: row.distance,
    relative_velocity: row.relative_velocity,
    predicted_status: row.predicted_status,
  }));
  const total = orderedHistory.length;

  return (
    <section className="panel mainPanel">
      <div className="historyViewHeader">
        <h2>Statistics</h2>
        <p>Visual summary of prediction distribution, TTC behavior, and sensor trends.</p>
      </div>

      {total === 0 ? (
        <div className="historyCard">
          <p>No predictions available for statistics.</p>
        </div>
      ) : (
        <div className="statsLayout">
          <ChartFrame title="Pie Chart for Status Distribution">
            <PieChart counts={counts} total={total} />
          </ChartFrame>

          <ChartFrame title="Bar Chart for Counts by Class">
            <BarChart counts={counts} />
          </ChartFrame>

          <ChartFrame title="Line Chart for TTC Over Time">
            <PolylineChart
              points={ttcPoints}
              color="#2e5fa3"
              yFormatter={(value) => `${value.toFixed(1)} s`}
              emptyText="Not enough TTC data available."
            />
          </ChartFrame>

          <ChartFrame title="Line Chart for Prediction Trend Over Time">
            <PolylineChart
              points={trendPoints}
              color="#7c3aed"
              yFormatter={(value) => {
                if (value >= 3.5) return "COL";
                if (value >= 2.5) return "HIGH";
                if (value >= 1.5) return "RISK";
                return "SAFE";
              }}
              emptyText="Not enough prediction trend data available."
            />
          </ChartFrame>

          <ChartFrame title="Histogram for Distance Values">
            <Histogram values={distanceValues} />
          </ChartFrame>

          <ChartFrame title="Scatter Plot of Distance vs Relative Velocity">
            <ScatterPlot points={scatterPoints} />
          </ChartFrame>
        </div>
      )}
    </section>
  );
}

function App() {
  const [form, setForm] = useState(initialForm);
  const [result, setResult] = useState(null);
  const [loading, setLoading] = useState(false);
  const [error, setError] = useState(null);
  const [submittedData, setSubmittedData] = useState(null);
  const [history, setHistory] = useState([]);
  const [activeView, setActiveView] = useState("predict");
  const [histLoading, setHistLoading] = useState(false);

  const handleChange = (e) => {
    setForm({ ...form, [e.target.name]: e.target.value });
    setError(null);
  };

  const resetForm = () => {
    setForm(initialForm);
    setResult(null);
    setError(null);
    setSubmittedData(null);
  };

  const handleSubmit = async (e) => {
    e.preventDefault();
    setLoading(true);
    setError(null);
    setResult(null);

    if (form.distance === "" || form.relative_velocity === "") {
      setError("Distance and relative velocity are required.");
      setLoading(false);
      return;
    }

    const payload = {
      distance: parseFloat(form.distance),
      relative_velocity: parseFloat(form.relative_velocity),
    };

    try {
      const response = await fetch(`${API_BASE}/predict`, {
        method: "POST",
        headers: { "Content-Type": "application/json" },
        body: JSON.stringify(payload),
      });

      if (!response.ok) {
        throw new Error("Prediction failed.");
      }

      const data = await response.json();
      setResult(data);
      setSubmittedData(payload);
      setForm(initialForm);
    } catch (err) {
      setError(err.message);
    } finally {
      setLoading(false);
    }
  };

  const fetchHistory = async (limit = 20) => {
    setHistLoading(true);
    try {
      const res = await fetch(`${API_BASE}/history?limit=${limit}`);
      setHistory(await res.json());
    } catch {
      setHistory([]);
    } finally {
      setHistLoading(false);
    }
  };

  const switchView = (view) => {
    setActiveView(view);
    if (view === "history") {
      fetchHistory(20);
    }
    if (view === "statistics") {
      fetchHistory(100);
    }
  };

  return (
    <div className="page">
      <header className="header">
        <h1>Vehicle Safety Prediction</h1>
        <p>ADAS-style risk estimation from distance and relative velocity</p>
      </header>

      <main className="dashboardSingle">
        <div className="viewSwitch">
          <button
            type="button"
            className={`viewTab ${activeView === "predict" ? "activeTab" : ""}`}
            onClick={() => switchView("predict")}
          >
            Predict
          </button>
          <button
            type="button"
            className={`viewTab ${activeView === "history" ? "activeTab" : ""}`}
            onClick={() => switchView("history")}
          >
            History
          </button>
          <button
            type="button"
            className={`viewTab ${activeView === "statistics" ? "activeTab" : ""}`}
            onClick={() => switchView("statistics")}
          >
            Statistics
          </button>
        </div>

        {activeView === "predict" ? (
          <PredictView
            form={form}
            loading={loading}
            error={error}
            result={result}
            submittedData={submittedData}
            onChange={handleChange}
            onSubmit={handleSubmit}
            onReset={resetForm}
          />
        ) : activeView === "history" ? (
          <HistoryView history={history} histLoading={histLoading} />
        ) : (
          <StatisticsView history={history} histLoading={histLoading} />
        )}
      </main>

      <footer className="footer">
        Vehicle Safety Prediction System · FastAPI + React
      </footer>
    </div>
  );
}

export default App;
